mapper.select:
    SELECT * FROM (
        SELECT ROWNUM AS rnum, subquery.* FROM (
          	SELECT i.inquiry_number, i.answer_status, i.inquiry_title,
			u.user_nickname, i.inquiry_date
			FROM ddd_inquiry i JOIN ddd_user u 
			ON i.user_number = u.user_number
			ORDER BY i.answer_status ASC, i.inquiry_date ASC
        ) subquery
    ) 
    WHERE rnum BETWEEN #{startRow} AND #{endRow}

mapper.update:
UPDATE DDD_INQUIRY
SET
ANSWER_POST = #{answerPost}
,ANSWER_DATE = sysdate , ANSWER_STATUS =
'Y'
WHERE INQUIRY_NUMBER = #{inquiryNumber}
